module top_module(
  input [3:0] data_in,
  input shift_in,
  input load,
  input clk,
  output reg [3:0] data_out
);reg [3:0] shift_reg;

  always @(posedge clk) begin
    if (load) begin
      shift_reg <= data_in;
    end else begin
      shift_reg <= {shift_reg[2:0], shift_in};
    end
  end

  wire __data_out_tmp = shift_reg;
  assign data_out = __data_out_tmp;

endmodule
